/**
 * CheckpointService — R2 检查点管理（Sprint 4 · V3.7）
 * Schema: task_checkpoints (12字段, 5状态: pending→submitted→passed/rejected→overdue)
 */
import {
  Injectable, NotFoundException, BadRequestException,
} from '@nestjs/common';
import { ApiProperty, ApiPropertyOptional } from '@nestjs/swagger';
import { IsString, IsOptional, IsNumber, IsIn, IsDateString, IsArray, MaxLength } from 'class-validator';
import { Type } from 'class-transformer';
import { PrismaService } from '../../prisma';

export class CreateCheckpointDto {
  @ApiProperty() @IsString() @MaxLength(50) name: string;
  @ApiProperty() @IsIn(['progress_check', 'quality_gate']) type: string;
  @ApiProperty() @IsDateString() plannedDate: string;
  @ApiProperty() @IsNumber() reviewerId: number;
  @ApiPropertyOptional() @IsOptional() @IsString() @MaxLength(200) description?: string;
}

export class SubmitCheckpointDto {
  @ApiProperty() @IsString() submitContent: string;
  @ApiPropertyOptional() @IsOptional() @IsArray() submitAttachments?: string[];
}

export class ReviewCheckpointDto {
  @ApiProperty() @IsIn(['passed', 'rejected']) result: string;
  @ApiPropertyOptional() @IsOptional() @IsString() reviewComment?: string;
}

@Injectable()
export class CheckpointService {
  constructor(private readonly prisma: PrismaService) {}

  async list(taskId: number) {
    const items = await this.prisma.taskCheckpoint.findMany({
      where: { taskId: BigInt(taskId) },
      orderBy: { sortOrder: 'asc' },
    });
    return items.map(c => this.serialize(c));
  }

  async create(taskId: number, dto: CreateCheckpointDto) {
    const maxSort = await this.prisma.taskCheckpoint.aggregate({
      where: { taskId: BigInt(taskId) },
      _max: { sortOrder: true },
    });
    const cp = await this.prisma.taskCheckpoint.create({
      data: {
        taskId: BigInt(taskId),
        name: dto.name,
        type: dto.type as any,
        plannedDate: new Date(dto.plannedDate),
        reviewerId: BigInt(dto.reviewerId),
        description: dto.description,
        sortOrder: (maxSort._max.sortOrder ?? 0) + 1,
      },
    });
    return { checkpointId: Number(cp.id) };
  }

  async submit(checkpointId: number, dto: SubmitCheckpointDto) {
    const cp = await this.prisma.taskCheckpoint.findUnique({ where: { id: BigInt(checkpointId) } });
    if (!cp) throw new NotFoundException('检查点不存在');
    if (!['pending', 'rejected'].includes(cp.status)) throw new BadRequestException('当前状态不允许提交');

    await this.prisma.taskCheckpoint.update({
      where: { id: BigInt(checkpointId) },
      data: {
        status: 'submitted',
        submitContent: dto.submitContent,
        submitAttachments: dto.submitAttachments || [],
        submittedAt: new Date(),
        revisionCount: cp.status === 'rejected' ? { increment: 1 } : undefined,
      },
    });
    return { checkpointId, status: 'submitted' };
  }

  async review(checkpointId: number, dto: ReviewCheckpointDto) {
    const cp = await this.prisma.taskCheckpoint.findUnique({ where: { id: BigInt(checkpointId) } });
    if (!cp) throw new NotFoundException('检查点不存在');
    if (cp.status !== 'submitted') throw new BadRequestException('当前状态不允许审核');

    await this.prisma.taskCheckpoint.update({
      where: { id: BigInt(checkpointId) },
      data: {
        status: dto.result as any,
        reviewComment: dto.reviewComment,
        reviewedAt: new Date(),
      },
    });
    return { checkpointId, status: dto.result };
  }

  async delete(checkpointId: number) {
    await this.prisma.taskCheckpoint.delete({ where: { id: BigInt(checkpointId) } });
    return { deleted: true };
  }

  private serialize(c: any) {
    return {
      id: Number(c.id), taskId: Number(c.taskId), name: c.name, type: c.type,
      plannedDate: c.plannedDate, reviewerId: Number(c.reviewerId),
      description: c.description, status: c.status,
      submitContent: c.submitContent, submitAttachments: c.submitAttachments,
      submittedAt: c.submittedAt, reviewComment: c.reviewComment, reviewedAt: c.reviewedAt,
      revisionCount: c.revisionCount, sortOrder: c.sortOrder,
    };
  }
}

/**
 * CommentService — R2 任务评论（Sprint 4 · V3.7）
 * Schema: task_comments (10字段, 支持回复/嵌套/@提及/标记重要)
 */
import {
  Injectable, NotFoundException,
} from '@nestjs/common';
import { ApiProperty, ApiPropertyOptional } from '@nestjs/swagger';
import { IsString, IsOptional, IsNumber, IsArray, IsBoolean, MaxLength } from 'class-validator';
import { Type } from 'class-transformer';
import { PrismaService } from '../../prisma';

export class CreateCommentDto {
  @ApiProperty() @IsString() @MaxLength(1000) content: string;
  @ApiPropertyOptional() @IsOptional() @IsNumber() parentId?: number;
  @ApiPropertyOptional() @IsOptional() @IsArray() attachments?: string[];
  @ApiPropertyOptional() @IsOptional() @IsBoolean() isImportant?: boolean;
}

@Injectable()
export class CommentService {
  constructor(private readonly prisma: PrismaService) {}

  async list(taskId: number, page = 1, pageSize = 50) {
    const where = { taskId: BigInt(taskId), isDeleted: false };
    const [list, total] = await Promise.all([
      this.prisma.taskComment.findMany({
        where, skip: (page - 1) * pageSize, take: pageSize,
        orderBy: { createdAt: 'desc' },
      }),
      this.prisma.taskComment.count({ where }),
    ]);
    return { list: list.map(c => this.serialize(c)), total, page, pageSize };
  }

  async create(taskId: number, authorType: string, authorId: number, dto: CreateCommentDto) {
    const comment = await this.prisma.taskComment.create({
      data: {
        taskId: BigInt(taskId),
        authorType: authorType as any,
        authorId: BigInt(authorId),
        content: dto.content.replace(/<[^>]*>/g, ''), // XSS防护：去除HTML标签
        parentId: dto.parentId ? BigInt(dto.parentId) : null,
        attachments: dto.attachments || [],
        isImportant: dto.isImportant || false,
      },
    });

    // 解析@提及 — 格式: @[用户名](userId)
    const mentions = dto.content.match(/@\[([^\]]+)\]\((\d+)\)/g);
    // TODO: C19 事件 → R4 通知

    return { commentId: Number(comment.id) };
  }

  async softDelete(commentId: number, userId: number) {
    const c = await this.prisma.taskComment.findUnique({ where: { id: BigInt(commentId) } });
    if (!c) throw new NotFoundException('评论不存在');
    if (Number(c.authorId) !== userId) throw new NotFoundException('无权删除');

    await this.prisma.taskComment.update({
      where: { id: BigInt(commentId) },
      data: { isDeleted: true },
    });
    return { deleted: true };
  }

  private serialize(c: any) {
    return {
      id: Number(c.id), taskId: Number(c.taskId),
      parentId: c.parentId ? Number(c.parentId) : null,
      authorType: c.authorType, authorId: Number(c.authorId),
      content: c.content, attachments: c.attachments,
      isImportant: c.isImportant, createdAt: c.createdAt,
    };
  }
}

/**
 * IssueService — R2 问题上报（Sprint 4 · V3.7）
 * Schema: task_issues (13字段, 4状态: open→in_progress→resolved→closed)
 * SLA: 首次响应 ≤24h, 超时标记 sla_breached
 */
import {
  Injectable, NotFoundException, BadRequestException,
} from '@nestjs/common';
import { ApiProperty, ApiPropertyOptional } from '@nestjs/swagger';
import { IsString, IsOptional, IsIn, IsArray, MaxLength } from 'class-validator';
import { PrismaService } from '../../prisma';

export class CreateIssueDto {
  @ApiProperty() @IsString() @MaxLength(100) title: string;
  @ApiProperty() @IsIn(['requirement_unclear', 'technical_block', 'resource_missing', 'other']) type: string;
  @ApiProperty() @IsString() description: string;
  @ApiPropertyOptional() @IsOptional() @IsArray() attachments?: string[];
}

export class UpdateIssueDto {
  @ApiPropertyOptional() @IsOptional() @IsIn(['open', 'in_progress', 'resolved', 'closed']) status?: string;
  @ApiPropertyOptional() @IsOptional() @IsString() response?: string; // 回复内容
}

@Injectable()
export class IssueService {
  constructor(private readonly prisma: PrismaService) {}

  async list(taskId: number) {
    const items = await this.prisma.taskIssue.findMany({
      where: { taskId: BigInt(taskId) },
      orderBy: { createdAt: 'desc' },
    });
    return items.map(i => this.serialize(i));
  }

  async create(taskId: number, reporterType: string, reporterId: number, dto: CreateIssueDto) {
    const issue = await this.prisma.taskIssue.create({
      data: {
        taskId: BigInt(taskId),
        reporterType: reporterType as any,
        reporterId: BigInt(reporterId),
        title: dto.title,
        type: dto.type as any,
        description: dto.description.replace(/<[^>]*>/g, ''), // XSS防护
        attachments: dto.attachments || [],
      },
    });
    // TODO: C20 事件 → R4 通知
    return { issueId: Number(issue.id) };
  }

  async update(issueId: number, dto: UpdateIssueDto) {
    const issue = await this.prisma.taskIssue.findUnique({ where: { id: BigInt(issueId) } });
    if (!issue) throw new NotFoundException('问题不存在');

    const data: any = {};
    if (dto.status) {
      data.status = dto.status;
      // 首次响应记录
      if (dto.status === 'in_progress' && !issue.firstResponseAt) {
        data.firstResponseAt = new Date();
      }
      if (dto.status === 'resolved') {
        data.resolvedAt = new Date();
      }
    }

    await this.prisma.taskIssue.update({ where: { id: BigInt(issueId) }, data });
    return { issueId, status: dto.status ?? issue.status };
  }

  /** SLA检查(被cron调用): 超24h未响应→标记breached */
  async checkSla() {
    const threshold = new Date(Date.now() - 24 * 3600 * 1000);
    const result = await this.prisma.taskIssue.updateMany({
      where: {
        status: 'open',
        firstResponseAt: null,
        slaBreached: false,
        createdAt: { lt: threshold },
      },
      data: { slaBreached: true },
    });
    return result.count;
  }

  private serialize(i: any) {
    return {
      id: Number(i.id), taskId: Number(i.taskId),
      reporterType: i.reporterType, reporterId: Number(i.reporterId),
      title: i.title, type: i.type, description: i.description,
      attachments: i.attachments, status: i.status,
      firstResponseAt: i.firstResponseAt, resolvedAt: i.resolvedAt,
      slaBreached: i.slaBreached, createdAt: i.createdAt,
    };
  }
}

