import {
  Injectable,
  BadRequestException,
  NotFoundException,
  ForbiddenException,
  Logger,
} from '@nestjs/common';
import { PrismaService } from '../../prisma';
import { assertTransition } from './task-status.machine';
import {
  CreateTaskDto,
  UpdateDraftDto,
  SetTaskRolesDto,
  TaskQueryDto,
} from './dto';

@Injectable()
export class TaskService {
  private readonly logger = new Logger(TaskService.name);

  constructor(private readonly prisma: PrismaService) {}

  // ================================================================
  // 创建任务（草稿）
  // ================================================================
  async createTask(companyId: number, userId: number, dto: CreateTaskDto) {
    const result = await this.prisma.$transaction(async (tx) => {
      const task = await tx.task.create({
        data: {
          companyId: BigInt(companyId),
          createdBy: BigInt(userId),
          title: dto.title,
          description: dto.description,
          taskMode: dto.taskMode as any,
          totalBudget: dto.totalBudget,
          startDate: dto.startDate ? new Date(dto.startDate) : undefined,
          endDate: dto.endDate ? new Date(dto.endDate) : undefined,
          address: dto.address,
          projectId: dto.projectId ? BigInt(dto.projectId) : undefined,
          status: 'draft',
          // V3.7
          priority: (dto.priority as any) || 'p2',
          acceptanceCriteria: dto.acceptanceCriteria,
        },
      });

      // 如果同时传了角色列表
      if (dto.roles && dto.roles.length > 0) {
        await tx.taskRole.createMany({
          data: dto.roles.map((r) => ({
            taskId: task.id,
            roleName: r.roleName,
